     6→
     7→#ifndef _SOFA_PBRPC_RPC_SERVER_MESSAGE_STREAM_H_
     8→#define _SOFA_PBRPC_RPC_SERVER_MESSAGE_STREAM_H_
     9→
    10→#include <deque>
    11→
    12→#include <sofa/pbrpc/rpc_error_code.h>
    13→#include <sofa/pbrpc/rpc_byte_stream.h>
    14→#include <sofa/pbrpc/rpc_message_header.h>
    15→#include <sofa/pbrpc/buffer.h>
    16→#include <sofa/pbrpc/tran_buf_pool.h>
    17→#include <sofa/pbrpc/flow_controller.h>
    18→#include <sofa/pbrpc/rpc_request_parser.h>
    19→#include <sofa/pbrpc/string_utils.h>
    20→
    21→namespace sofa {
    22→namespace pbrpc {
    23→
    24→// The "SendCookie" type should has default constructor, and should be copyable.
    25→template <typename SendCookie>
    26→class RpcServerMessageStream : public RpcByteStream
    27→{
    28→public:
    29→    enum RoleType
    30→    {
    31→        ROLE_TYPE_SERVER = 0,
    32→        ROLE_TYPE_CLIENT = 1,
    33→    };
    34→
    35→public:
    36→    RpcServerMessageStream(RoleType role_type,
    37→                     IOService& io_service,
    38→                     const RpcEndpoint& endpoint)
    39→        : RpcByteStream(io_service, endpoint)
    40→        , _role_type(role_type)
    41→        , _pending_message_count(0)
    42→        , _pending_data_size(0)
    43→        , _pending_buffer_size(0)
    44→        , _swapped_message_count(0)
    45→        , _swapped_data_size(0)
    46→        , _swapped_buffer_size(0)
    47→        , _max_pending_buffer_size(0)
    48→        , _read_quota_token(1)
    49→        , _write_quota_token(1)
    50→        , _total_sent_count(0)
    51→        , _total_sent_size(0)
    52→        , _total_received_count(0)
    53→        , _total_received_size(0)
    54→        , _sent_size(0)
    55→        , _sending_data(NULL)
    56→        , _sending_size(0)
    57→        , _magic_string_recved_bytes(0)
    58→        , _cur_recved_bytes(0)
    59→        , _tran_buf(NULL)
    60→        , _receiving_data(NULL)
    61→        , _receiving_size(0)
    62→        , _send_token(TOKEN_FREE)
    63→        , _receive_token(TOKEN_FREE)
    64→    {
    65→        RpcRequestParser::RegisteredParsers(&_rpc_request_parsers);
    66→    }
    67→
    68→    virtual ~RpcServerMessageStream()
    69→    {
    70→        if (_tran_buf != NULL)
    71→        {
    72→            TranBufPool::free(_tran_buf);
    73→            _tran_buf = NULL;
    74→        }
    75→    }
    76→
    77→    // Async send message to the remote endpoint. The message may be first
    78→    // put into a pending queue if the channel is busy at that time.
    79→    //
    80→    // Before starting sending data, the hook function "on_sending" will
    81→    // be called to check if the message still need to be sent.
    82→    //
    83→    // If send succeed, callback "on_sent" will be called;
    84→    // else, callback "on_send_failed" will be called. 
    85→    //
    86→    // @param message  the message to send, including header, meta and data.
    87→    // @param cookie  a cookie affiliated to the message, which can carry some
    88→    //                user's customized info. It will not be sent, but would
    89→    //                be passed to the callback function.
    90→    void async_send_message(
    91→            const ReadBufferPtr& message,
    92→            const SendCookie& cookie)
    93→    {
    94→        SOFA_PBRPC_FUNCTION_TRACE;
    95→
    96→        if (is_closed())
    97→        {
    98→            on_send_failed(RPC_ERROR_CONNECTION_CLOSED, message, cookie);
    99→            return;
   100→        }
   101→
   102→        put_into_pending_queue(message, cookie);
   103→
   104→        try_start_send();
   105→    }
   106→
   107→    // Set the flow controller.
   108→    void set_flow_controller(const FlowControllerPtr& flow_controller)
   109→    {
   110→        _flow_controller = flow_controller;
   111→    }
   112→
   113→    // Set the max size of pending buffer for send.
   114→    void set_max_pending_buffer_size(int64 max_pending_buffer_size)
   115→    {
   116→        _max_pending_buffer_size = max_pending_buffer_size;
   117→    }
   118→
   119→    // Get the max size of pending buffer for send.
   120→    int64 max_pending_buffer_size() const
   121→    {
   122→        return _max_pending_buffer_size;
   123→    }
   124→
   125→    // Get the current count of messages in the pending queue.
   126→    int64 pending_message_count() const
   127→    {
   128→        return _pending_message_count + _swapped_message_count;
   129→    }
   130→
   131→    // Get the current data size of messages in the pending queue.
   132→    int64 pending_data_size() const
   133→    {
   134→        return _pending_data_size + _swapped_data_size;
   135→    }
   136→
   137→    // Get the current buffer size occupied by the pending queue.
   138→    // This size may be larger than "pending_data_size".
   139→    int64 pending_buffer_size() const
   140→    {
   141→        return _pending_buffer_size + _swapped_buffer_size;
   142→    }
   143→
   144→    // Trigger receiving operator.
   145→    // @return true if suceessfully triggered
   146→    virtual bool trigger_receive()
   147→    {
   148→        _read_quota_token = 1;
   149→        return try_start_receive();
   150→    }
   151→
   152→    // Trigger sending operator.
   153→    // @return true if suceessfully triggered
   154→    virtual bool trigger_send()
   155→    {
   156→        _write_quota_token = 1;
   157→        return try_start_send();
   158→    }
   159→
   160→    // Get read quota token used for sorting the trigger order.
   161→    // Always no more than 0.
   162→    int read_quota_token() const
   163→    {
   164→        return _read_quota_token;
   165→    }
   166→
   167→    // Get write quota token used for sorting the trigger order.
   168→    // Always no more than 0.
   169→    int write_quota_token() const
   170→    {
   171→        return _write_quota_token;
   172→    }
   173→
   174→protected:
   175→    // Hook function on the point of starting the sending.
   176→    //
   177→    // If return true, go ahead with the sending;
   178→    // else, cancel the sending.
   179→    //
   180→    // This hook may be useful when the message stayed in a sending waiting
   181→    // queue for some time, but when dequed, it is already timeout.
   182→    virtual bool on_sending(
   183→            const ReadBufferPtr& message,
   184→            const SendCookie& cookie) = 0;
   185→
   186→    // Hook function when send message succeed.
   187→    virtual void on_sent(
   188→            const ReadBufferPtr& message,
   189→            const SendCookie& cookie) = 0;
   190→
   191→    // Hook function when send message failed.
   192→    virtual void on_send_failed(
   193→            RpcErrorCode error_code,
   194→            const ReadBufferPtr& message,
   195→            const SendCookie& cookie) = 0;
   196→
   197→    // Hook function when received message.
   198→    // @param request the RPC request object.
   199→    virtual void on_received(
   200→            const RpcRequestPtr& request) = 0;
   201→
   202→private:
   203→    virtual bool on_connected()
   204→    {
   205→        SOFA_PBRPC_FUNCTION_TRACE;
   206→
   207→        reset_receiving_env();
   208→        // prepare receiving
   209→        if (!reset_tran_buf())
   210→        {
   211→            close("out of memory");
   212→            return false;
   213→        }
   214→        return true;
   215→    }
   216→
   217→    // Callback of "async_read_some()".
   218→    virtual void on_read_some(
   219→            const boost::system::error_code& error,
   220→            std::size_t bytes_transferred)
   221→    {
   222→        SOFA_PBRPC_FUNCTION_TRACE;
   223→
   224→        if (error)
   225→        {
   226→            if (error != boost::asio::error::eof)
   227→            {
   228→#if defined( LOG )
   229→                LOG(ERROR) <<  "on_read_some(): " << RpcEndpointToString(_remote_endpoint)
   230→                           << ": read error: " << error.message();
   231→#else
   232→                SLOG(ERROR, "on_read_some(): %s: read error: %s",
   233→                        RpcEndpointToString(_remote_endpoint).c_str(),
   234→                        error.message().c_str());
   235→#endif
   236→            }
   237→
   238→            close(error.message());
   239→            return;
   240→        }
   241→
   242→        _last_rw_ticks = _ticks;
   243→        ++_total_received_count;
   244→        _total_received_size += bytes_transferred;
   245→
   246→        std::deque<RpcRequestPtr> received_messages;
   247→        if (!split_and_process_message(_receiving_data,
   248→                    static_cast<int>(bytes_transferred), &received_messages))
   249→        {
   250→            close("broken stream");
   251→            return;
   252→        }
   253→
   254→        _receiving_data += bytes_transferred;
   255→        _receiving_size -= bytes_transferred;
   256→
   257→        // check if current tran buf is used out
   258→        if (_receiving_size == 0 && !reset_tran_buf())
   259→        {
   260→            close("out of memory");
   261→            return;
   262→        }
   263→
   264→        // release token
   265→        atomic_comp_swap(&_receive_token, TOKEN_FREE, TOKEN_LOCK);
   266→
   267→        // trigger next receive
   268→        try_start_receive();
   269→
   270→        // process messages
   271→        while (!is_closed() && !received_messages.empty())
   272→        {
   273→            on_received(received_messages.front());
   274→            received_messages.pop_front();
   275→        }
   276→    }
   277→
   278→    // Hook of "async_write_some()".
   279→    virtual void on_write_some(
   280→            const boost::system::error_code& error,
   281→            std::size_t bytes_transferred)
   282→    {
   283→        SOFA_PBRPC_FUNCTION_TRACE;
   284→
   285→        if (error)
   286→        {
   287→#if defined( LOG )
   288→            LOG(ERROR) << "on_write_some(): " << RpcEndpointToString(_remote_endpoint)
   289→                       << ": write error: " << error.message();
   290→#else
   291→            SLOG(ERROR, "on_write_some(): %s: write error: %s",
   292→                    RpcEndpointToString(_remote_endpoint).c_str(),
   293→                    error.message().c_str());
   294→#endif
   295→
   296→            on_send_failed(RPC_ERROR_CHANNEL_BROKEN,
   297→                    _sending_message, _sending_cookie);
   298→            clear_sending_env();
   299→
   300→            close(error.message());
   301→            return;
   302→        }
   303→
   304→        _last_rw_ticks = _ticks;
   305→        _sent_size += bytes_transferred;
   306→        ++_total_sent_count;
   307→        _total_sent_size += bytes_transferred;
   308→
   309→        if (static_cast<int>(bytes_transferred) == _sending_size)
   310→        {
   311→            // seek to the next buf handle
   312→            if (_sending_message->Next(
   313→                        reinterpret_cast<const void**>(&_sending_data),
   314→                        &_sending_size))
   315→            {
   316→                // more buf to send
   317→                async_write_some(_sending_data, _sending_size);
   318→            }
   319→            else
   320→            {
   321→                // current message is completely sent
   322→                SCHECK_EQ(_sent_size, _sending_message->ByteCount());
   323→
   324→                // call hook function
   325→                on_sent(_sending_message, _sending_cookie);
   326→                clear_sending_env();
   327→
   328→                // release token
   329→                atomic_comp_swap(&_send_token, TOKEN_FREE, TOKEN_LOCK);
   330→
   331→                // trigger next send
   332→                try_start_send();
   333→
   334→                // trigger next receive if it is server, because receiving operator
   335→                // in server may be hanged for pending buffer full.
   336→                if (_role_type == ROLE_TYPE_SERVER)
   337→                    try_start_receive();
   338→            }
   339→        }
   340→        else
   341→        {
   342→            // only sent part of the data
   343→            SCHECK_LT(static_cast<int>(bytes_transferred), _sending_size);
   344→            
   345→            // start sending the remaining data
   346→            _sending_data += bytes_transferred;
   347→            _sending_size -= bytes_transferred;
   348→            async_write_some(_sending_data, _sending_size);
   349→        }
   350→    }
   351→
   352→    // Put an item into back of the pending queue.
   353→    //
   354→    // @return false if the pending queue is full.
   355→    void put_into_pending_queue(
   356→            const ReadBufferPtr& message,
   357→            const SendCookie& cookie)
   358→    {
   359→        SOFA_PBRPC_FUNCTION_TRACE;
   360→
   361→        ScopedLocker<FastLock> _(_pending_lock);
   362→        _pending_calls.push_back(PendingItem(message, cookie));
   363→        ++_pending_message_count;
   364→        _pending_data_size += message->TotalCount();
   365→        _pending_buffer_size += message->BlockCount() * TranBufPool::block_size();
   366→    }
   367→
   368→    // Insert an item into front of the pending queue.
   369→    //
   370→    // @return false if the pending queue is full.
   371→    void insert_into_pending_queue(
   372→            const ReadBufferPtr& message,
   373→            const SendCookie& cookie)
   374→    {
   375→        SOFA_PBRPC_FUNCTION_TRACE;
   376→
   377→        _swapped_calls.push_front(PendingItem(message, cookie));
   378→        ++_swapped_message_count;
   379→        _swapped_data_size += message->TotalCount();
   380→        _swapped_buffer_size += message->BlockCount() * TranBufPool::block_size();
   381→    }
   382→
   383→    // Get an item from the pending queue.
   384→    //
   385→    // @return false if the pending queue is empty.
   386→    bool get_from_pending_queue(
   387→            ReadBufferPtr* message,
   388→            SendCookie* cookie)
   389→    {
   390→        SOFA_PBRPC_FUNCTION_TRACE;
   391→
   392→        if (_swapped_calls.empty() && _pending_message_count > 0)
   393→        {
   394→            // swap from _pending_calls
   395→            ScopedLocker<FastLock> _(_pending_lock);
   396→            if (!_pending_calls.empty())
   397→            {
   398→                _swapped_calls.swap(_pending_calls);
   399→                _swapped_message_count = _pending_message_count;
   400→                _swapped_data_size = _pending_data_size;
   401→                _swapped_buffer_size = _pending_buffer_size;
   402→                _pending_message_count = 0;
   403→                _pending_data_size = 0;
   404→                _pending_buffer_size = 0;
   405→            }
   406→        }
   407→
   408→        if (!_swapped_calls.empty())
   409→        {
   410→            // fetch the top one
   411→            *message = _swapped_calls.front().message;
   412→            *cookie = _swapped_calls.front().cookie;
   413→            _swapped_calls.pop_front();
   414→            // update stats
   415→            --_swapped_message_count;
   416→            _swapped_data_size -= (*message)->TotalCount();
   417→            _swapped_buffer_size -= (*message)->BlockCount() * TranBufPool::block_size();
   418→            return true;
   419→        }
   420→
   421→        // no message found
   422→        SCHECK_EQ(0, _swapped_message_count);
   423→        SCHECK_EQ(0, _swapped_data_size);
   424→        SCHECK_EQ(0, _swapped_buffer_size);
   425→        return false;
   426→    }
   427→
   428→    // Try to start receiving messages.  It will check that receiving is allowed,
   429→    // and try to acquire the reveive token.
   430→    //
   431→    // If failed, the receiving is ignored.
   432→    // If succeed, the token must be acquired.
   433→    bool try_start_receive()
   434→    {
   435→        SOFA_PBRPC_FUNCTION_TRACE;
   436→
   437→        if (_receive_token == TOKEN_LOCK)
   438→        {
   439→            // no token
   440→            return false;
   441→        }
   442→
   443→        if (_read_quota_token <= 0)
   444→        {
   445→            // last acquire quota failed
   446→            return false;
   447→        }
   448→
   449→        if (_role_type == ROLE_TYPE_SERVER
   450→                && _pending_buffer_size > _max_pending_buffer_size)
   451→        {
   452→            // sending buffer full, should suspend receiving to wait
   453→            return false;
   454→        }
   455→
   456→        bool started = false;
   457→        if (is_connected() 
   458→                && atomic_comp_swap(&_receive_token, TOKEN_LOCK, TOKEN_FREE) == TOKEN_FREE)
   459→        {
   460→            SCHECK(_receiving_data != NULL);
   461→            SCHECK(_receiving_size > 0);
   462→            if ((_read_quota_token = _flow_controller->acquire_read_quota(_receiving_size)) <= 0)
   463→            {
   464→                // no network quota
   465→                atomic_comp_swap(&_receive_token, TOKEN_FREE, TOKEN_LOCK);
   466→            }
   467→            else
   468→            {
   469→                // now start receive
   470→                async_read_some(_receiving_data, _receiving_size);
   471→                started = true;
   472→            }
   473→        }
   474→        return started;
   475→    }
   476→
   477→    // Try to start sending a message.  It will check that sending is allowed,
   478→    // and try to acquire the send token.
   479→    //
   480→    // If failed, the sending is ignored.
   481→    // If succeed, the token must be acquired.
   482→    bool try_start_send()
   483→    {
   484→        SOFA_PBRPC_FUNCTION_TRACE;
   485→
   486→        if (_send_token == TOKEN_LOCK)
   487→        {
   488→            // no token
   489→            return false;
   490→        }
   491→
   492→        if (_write_quota_token <= 0)
   493→        {
   494→            // last acquire quota failed
   495→            return false;
   496→        }
   497→
   498→        bool started = false;
   499→        while (is_connected() 
   500→                && atomic_comp_swap(&_send_token, TOKEN_LOCK, TOKEN_FREE) == TOKEN_FREE)
   501→        {
   502→            if (get_from_pending_queue(&_sending_message, &_sending_cookie))
   503→            {
   504→                if (!on_sending(_sending_message, _sending_cookie))
   505→                {
   506→                    // need not send
   507→                    on_send_failed(RPC_ERROR_REQUEST_CANCELED,
   508→                            _sending_message, _sending_cookie);
   509→                    clear_sending_env();
   510→
   511→                    atomic_comp_swap(&_send_token, TOKEN_FREE, TOKEN_LOCK);
   512→                }
   513→                else if ((_write_quota_token = _flow_controller->acquire_write_quota(
   514→                                _sending_message->TotalCount())) <= 0)
   515→                {
   516→                    // no network quota
   517→                    insert_into_pending_queue(_sending_message, _sending_cookie);
   518→                    clear_sending_env();
   519→
   520→                    atomic_comp_swap(&_send_token, TOKEN_FREE, TOKEN_LOCK);
   521→                    break;
   522→                }
   523→                else
   524→                {
   525→                    // now send
   526→                    _sent_size = 0;
   527→                    bool ret = _sending_message->Next(
   528→                            reinterpret_cast<const void**>(&_sending_data), &_sending_size);
   529→                    SCHECK(ret);
   530→                    async_write_some(_sending_data, _sending_size);
   531→                    started = true;
   532→                    break;
   533→                }
   534→            }
   535→            else
   536→            {
   537→                // empty pending queue
   538→                atomic_comp_swap(&_send_token, TOKEN_FREE, TOKEN_LOCK);
   539→                break;
   540→            }
   541→        }
   542→        return started;
   543→    }
   544→
   545→    // Process "data", split message, and store found messages.
   546→    //
   547→    // @return true if no error occured, and found messages are stored
   548→    //              in "received_messages", may be empty.
   549→    // @return false if error occured, for example bad message stream.
   550→    bool split_and_process_message(char* data, int size,
   551→            std::deque<RpcRequestPtr>* received_messages)
   552→    {
   553→        SOFA_PBRPC_FUNCTION_TRACE;
   554→
   555→        while (size > 0)
   556→        {
   557→            int consumed;
   558→            if (_magic_string_recved_bytes < 4)
   559→            {
   560→                // read magic string
   561→                consumed = std::min(size, 4 - _magic_string_recved_bytes);
   562→                memcpy(_magic_string + _magic_string_recved_bytes, data, consumed);
   563→                _magic_string_recved_bytes += consumed;
   564→                _cur_recved_bytes += consumed;
   565→                if (_magic_string_recved_bytes < 4)
   566→                {
   567→                    return true;
   568→                }
   569→                data += consumed;
   570→                size -= consumed;
   571→                if (!choose_rpc_request_parser())
   572→                {
   573→                    // no parser identify the magic string
   574→                    return false;
   575→                }
   576→                if (size == 0)
   577→                {
   578→                    // no more data
   579→                    return true;
   580→                }
   581→            }
   582→            int ret = _current_rpc_request_parser->Parse(
   583→                    _tran_buf, size, data - _tran_buf, &consumed);
   584→            _cur_recved_bytes += consumed;
   585→            if (ret == 0)
   586→            {
   587→                return true;
   588→            }
   589→            else if (ret < 0)
   590→            {
   591→                return false;
   592→            }
   593→            data += consumed;
   594→            size -= consumed;
   595→            RpcRequestPtr request = _current_rpc_request_parser->GetRequest();
   596→            request->SetLocalEndpoint(_local_endpoint);
   597→            request->SetRemoteEndpoint(_remote_endpoint);
   598→            request->SetReceivedTime(ptime_now());
   599→            received_messages->push_back(request);
   600→            reset_receiving_env();
   601→        }
   602→        return true;
   603→    }
   604→
   605→    // Choose the proper request parser.
   606→    //
   607→    // @return false if no parser matched.
   608→    bool choose_rpc_request_parser()
   609→    {
   610→        // usually, one channal always use the same parser,
   611→        // so first try to use the parser used by the last request
   612→        if (_current_rpc_request_parser
   613→                && _current_rpc_request_parser->CheckMagicString(_magic_string))
   614→        {
   615→            return true;
   616→        }
   617→        // the last parser not match, then find in all parsers
   618→        std::vector<RpcRequestParserPtr>::const_iterator it = _rpc_request_parsers.begin();
   619→        std::vector<RpcRequestParserPtr>::const_iterator end = _rpc_request_parsers.end();
   620→        for (; it != end; ++it)
   621→        {
   622→            if ((*it)->CheckMagicString(_magic_string))
   623→            {
   624→                _current_rpc_request_parser = *it;
   625→                return true;
   626→            }
   627→        }
   628→        // no parser match, print error
   629→        std::string magic_str = StringUtils::c_escape_string(_magic_string, sizeof(_magic_string));
   630→#if defined( LOG )
   631→        LOG(ERROR) << "choose_rpc_request_parser(): " << RpcEndpointToString(_remote_endpoint)
   632→                   << ": un-identified magic string: " << magic_str;
   633→#else
   634→        SLOG(ERROR, "choose_rpc_request_parser(): %s: un-identified magic string: %s",
   635→                RpcEndpointToString(_remote_endpoint).c_str(), magic_str.c_str());
   636→#endif
   637→        _current_rpc_request_parser.reset();
   638→        return false;
   639→    }
   640→
   641→    // Clear temp variables for sending message.
   642→    void clear_sending_env()
   643→    {
   644→        _sending_message.reset();
   645→        _sending_cookie = SendCookie();
   646→        _sent_size = 0;
   647→        _sending_data = NULL;
   648→        _sending_size = 0;
   649→    }
   650→
   651→    // Clear temp variables for receiving message.
   652→    void reset_receiving_env()
   653→    {
   654→        if (_current_rpc_request_parser)
   655→        {
   656→            _current_rpc_request_parser->Reset();
   657→        }
   658→        _magic_string_recved_bytes = 0;
   659→        _cur_recved_bytes = 0;
   660→    }
   661→
   662→    // Reset tran buf variables for receiving message.
   663→    bool reset_tran_buf()
   664→    {
   665→        if (_tran_buf != NULL)
   666→        {
   667→            // free old buf, in fact just decrease ref count
   668→            TranBufPool::free(_tran_buf);
   669→            _tran_buf = NULL;
   670→        }
   671→
   672→        _tran_buf = reinterpret_cast<char*>(TranBufPool::malloc());
   673→        if(_tran_buf == NULL)
   674→        {
   675→#if defined( LOG )
   676→            LOG(ERROR) << "reset_tran_buf(): " << RpcEndpointToString(_remote_endpoint)
   677→                       << ": malloc buffer failed: out of memory";
   678→#else
   679→            SLOG(ERROR, "reset_tran_buf(): %s: malloc buffer failed: out of memory",
   680→                    RpcEndpointToString(_remote_endpoint).c_str());
   681→#endif
   682→            return false;
   683→        }
   684→        _receiving_data = reinterpret_cast<char*>(_tran_buf);
   685→        _receiving_size = TranBufPool::block_size();
   686→        return true;
   687→    }
   688→
   689→protected:
   690→    RoleType _role_type;
   691→
   692→private:
   693→    struct PendingItem
   694→    {
   695→        ReadBufferPtr message;
   696→        SendCookie cookie;
   697→        PendingItem(const ReadBufferPtr& _message,
   698→                    const SendCookie& _cookie)
   699→            : message(_message)
   700→            , cookie(_cookie) {}
   701→    };
   702→
   703→    // TODO improve sync queue performance
   704→    volatile int _pending_message_count;
   705→    volatile int64 _pending_data_size;
   706→    volatile int64 _pending_buffer_size;
   707→    std::deque<PendingItem> _pending_calls;
   708→    FastLock _pending_lock;
   709→    std::deque<PendingItem> _swapped_calls;
   710→    volatile int _swapped_message_count;
   711→    volatile int64 _swapped_data_size;
   712→    volatile int64 _swapped_buffer_size;
   713→
   714→    // flow control
   715→    FlowControllerPtr _flow_controller;
   716→    int64 _max_pending_buffer_size;
   717→    volatile int32 _read_quota_token; // <=0 means no quota 
   718→    volatile int32 _write_quota_token; // <=0 means no quota 
   719→    // statistics
   720→    int64 _total_sent_count;
   721→    int64 _total_sent_size;
   722→    int64 _total_received_count;
   723→    int64 _total_received_size;
   724→
   725→    // temp variables for sending message
   726→    ReadBufferPtr _sending_message; //current sending message
   727→    SendCookie _sending_cookie; // cookie of the message
   728→    int64 _sent_size; // current sent size of the message
   729→    const char* _sending_data; // current sending data, weak ptr
   730→    int _sending_size; // size of the current sending data
   731→
   732→    char _magic_string[4];
   733→    int _magic_string_recved_bytes;
   734→    int _cur_recved_bytes;
   735→
   736→    std::vector<RpcRequestParserPtr> _rpc_request_parsers;
   737→    RpcRequestParserPtr _current_rpc_request_parser;
   738→
   739→    // tran buf for reading data
   740→    char* _tran_buf; // strong ptr
   741→    char* _receiving_data; // weak ptr
   742→    int64 _receiving_size;
   743→
   744→    // send and receive token
   745→    static const int TOKEN_FREE = 0;
   746→    static const int TOKEN_LOCK = 1;
   747→    volatile int _send_token;
   748→    volatile int _receive_token;
   749→}; // class RpcServerMessageStream
   750→
   751→} // namespace pbrpc
   752→} // namespace sofa
   753→
   754→#endif // _SOFA_PBRPC_RPC_SERVER_MESSAGE_STREAM_H_
   755→
   756→/* vim: set ts=4 sw=4 sts=4 tw=100 */
   757→

